module.exports = {
  dbConfig: {
    host: 'localhost',
    user: 'user',
    password: 'password',
    database: 'blog_db'
  },
  jwtSecret: 'your_jwt_secret'
};

const { Pool } = require('pg');
const config = require('../config');

const pool = new Pool(config.dbConfig);

module.exports = {
  query: (text, params) => pool.query(text, params)
};

const jwt = require('jsonwebtoken');
const config = require('../config');

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (token == null) return res.sendStatus(401);

  jwt.verify(token, config.jwtSecret, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
}

module.exports = { authenticateToken };

const db = require('../database');
const auth = require('../auth');

async function getPosts(req, res) {
  try {
    const result = await db.query('SELECT * FROM posts');
    res.json(result.rows);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
}

async function getPost(req, res) {
  try {
    const id = parseInt(req.params.id);
    const result = await db.query('SELECT * FROM posts WHERE id = $1', [id]);
    if (result.rows.length === 0) return res.status(404).json({ error: 'Post not found' });
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
}

async function createPost(req, res) {
  try {
    const { title, content } = req.body;
    const result = await db.query('INSERT INTO posts (title, content) VALUES ($1, $2) RETURNING *', [title, content]);
    res.status(201).json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
}

async function updatePost(req, res) {
  try {
    const id = parseInt(req.params.id);
    const { title, content } = req.body;
    const result = await db.query('UPDATE posts SET title = $1, content = $2 WHERE id = $3 RETURNING *', [title, content, id]);
    if (result.rows.length === 0) return res.status(404).json({ error: 'Post not found' });
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
}

async function deletePost(req, res) {
  try {
    const id = parseInt(req.params.id);
    const result = await db.query('DELETE FROM posts WHERE id = $1', [id]);
    if (result.rows.length === 0) return res.status(404).json({ error: 'Post not found' });
    res.json({ message: 'Post deleted' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
}

module.exports = { getPosts, getPost, createPost, updatePost, deletePost };

const express = require('express');
const blog = require('../blog');
const auth = require('../auth');

const router = express.Router();

router.get('/api/blog/posts', blog.getPosts);
router.get('/api/blog/posts/:id', blog.getPost);
router.post('/api/blog/posts', auth.authenticateToken, blog.createPost);
router.put('/api/blog/posts/:id', auth.authenticateToken, blog.updatePost);
router.delete('/api/blog/posts/:id', auth.authenticateToken, blog.deletePost);

module.exports = router;

const express = require('express');
const config = require('./config');
const routes = require('./routes');

const app = express();
app.use(express.json());
app.use(routes);

app.listen(config.port, () => {
  console.log(`Server is running on port ${config.port}`);
});
